import boto3
import sys
from urllib.parse import urlparse

def create_sns_subscription(topic_arn, endpoint):
    """Create SNS subscription with basic validation"""
    try:
        sns = boto3.client('sns')
        response = sns.subscribe(
            TopicArn=topic_arn,
            Protocol='https',
            Endpoint=endpoint
        )
        return response
    except Exception as e:
        print(f"Error creating subscription: {e}")
        return None

def validate_endpoint(endpoint):
    """Basic endpoint validation"""
    try:
        parsed = urlparse(endpoint)
        return parsed.scheme == 'https' and parsed.netloc
    except Exception:
        return False

def main():
    if len(sys.argv) != 3:
        print("Usage: python script.py <topic_arn> <endpoint_url>")
        sys.exit(1)
    
    topic_arn = sys.argv[1]
    endpoint = sys.argv[2]
    
    # Validate endpoint
    if not validate_endpoint(endpoint):
        print("Error: Invalid endpoint URL")
        sys.exit(1)
    
    # Create subscription
    result = create_sns_subscription(topic_arn, endpoint)
    if result:
        print(f"Subscription created successfully: {result['SubscriptionArn']}")
    else:
        print("Failed to create subscription")

if __name__ == "__main__":
    main()